INSERT INTO `cms_pages` (`id`, `slug`, `title`, `meta_description`, `content_html`, `created_at`, `updated_at`) VALUES
(2, 'about', 'About Us', 'Learn about our dealership and team.', '<!-- Breads -->\r\n		<div class=\"container\">\r\n\r\n					<div data-elementor-type=\"wp-page\" data-elementor-id=\"2067\" class=\"elementor elementor-2067\">\r\n						<section class=\"elementor-section elementor-top-section elementor-element elementor-element-4fd4f1d elementor-section-boxed elementor-section-height-default elementor-section-height-default\" data-id=\"4fd4f1d\" data-element_type=\"section\">\r\n						<div class=\"elementor-container elementor-column-gap-default\">\r\n					<div class=\"elementor-column elementor-col-50 elementor-top-column elementor-element elementor-element-4fc0b1f\" data-id=\"4fc0b1f\" data-element_type=\"column\">\r\n			<div class=\"elementor-widget-wrap elementor-element-populated\">\r\n						<div class=\"elementor-element elementor-element-2ad78c5 elementor-widget elementor-widget-image\" data-id=\"2ad78c5\" data-element_type=\"widget\" data-widget_type=\"image.default\">\r\n				<div class=\"elementor-widget-container\">\r\n			<style>/*! elementor - v3.20.0 - 13-03-2024 */\r\n.elementor-widget-image{text-align:center}.elementor-widget-image a{display:inline-block}.elementor-widget-image a img[src$=\".svg\"]{width:48px}.elementor-widget-image img{vertical-align:middle;display:inline-block}</style>										<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/elementor/thumbs/about-us-1-529x290-1-pvnmhh9wanpya0e9qvigo84e27ok59uvpkb2nplxg4.jpeg\" alt=\"about-us-1-529x290\" loading=\"lazy\" />													</div>\r\n				</div>\r\n					</div>\r\n		</div>\r\n				<div class=\"elementor-column elementor-col-50 elementor-top-column elementor-element elementor-element-14f77ae\" data-id=\"14f77ae\" data-element_type=\"column\">\r\n			<div class=\"elementor-widget-wrap elementor-element-populated\">\r\n						<div class=\"elementor-element elementor-element-f5f5579 elementor-widget elementor-widget-text-editor\" data-id=\"f5f5579\" data-element_type=\"widget\" data-widget_type=\"text-editor.default\">\r\n				<div class=\"elementor-widget-container\">\r\n			<style>/*! elementor - v3.20.0 - 13-03-2024 */\r\n.elementor-widget-text-editor.elementor-drop-cap-view-stacked .elementor-drop-cap{background-color:#69727d;color:#fff}.elementor-widget-text-editor.elementor-drop-cap-view-framed .elementor-drop-cap{color:#69727d;border:3px solid;background-color:transparent}.elementor-widget-text-editor:not(.elementor-drop-cap-view-default) .elementor-drop-cap{margin-top:8px}.elementor-widget-text-editor:not(.elementor-drop-cap-view-default) .elementor-drop-cap-letter{width:1em;height:1em}.elementor-widget-text-editor .elementor-drop-cap{float:left;text-align:center;line-height:1;font-size:50px}.elementor-widget-text-editor .elementor-drop-cap-letter{display:inline-block}</style>				<h3>WELCOME TO THEÂ <span style=\"color: #ffb129;\">MOTORS</span></h3>\r\n<h5 style=\"margin-bottom: 22px; font-family: Montserrat, Arial;\">Before we get ahead of ourselves, we want to welcome you to Loeber Motors. While nothing can replace thing on-the-lot experience.</h5>\r\n<p style=\"margin-bottom: 26px; font-size:16px; line-height:30px;\">We appreciate you taking the time today to visit our web site. Our goal is to give you an interactive tour of our new and used inventory, as well as allow you to conveniently get a quote, schedule a service appointment, or apply for financing. The search for a luxury car is filled with high expectations. Undoubtedly, that has a lot to do with the vehicles you are considering, but at Motors, we think you should also have pretty high expectations for your dealership.</p>\r\n<span style=\"color: #888888;\"><em>Â â€” MIKEY DIOKLES, President of Motors</em></span>						</div>\r\n				</div>\r\n					</div>\r\n		</div>\r\n					</div>\r\n		</section>\r\n				<section class=\"elementor-section elementor-top-section elementor-element elementor-element-7ddb0c1 elementor-section-boxed elementor-section-height-default elementor-section-height-default\" data-id=\"7ddb0c1\" data-element_type=\"section\">\r\n						<div class=\"elementor-container elementor-column-gap-default\">\r\n					<div class=\"elementor-column elementor-col-50 elementor-top-column elementor-element elementor-element-140449d\" data-id=\"140449d\" data-element_type=\"column\">\r\n			<div class=\"elementor-widget-wrap elementor-element-populated\">\r\n						<div class=\"elementor-element elementor-element-7a1f682 elementor-widget elementor-widget-text-editor\" data-id=\"7a1f682\" data-element_type=\"widget\" data-widget_type=\"text-editor.default\">\r\n				<div class=\"elementor-widget-container\">\r\n							<h3>CORE VALUES</h3><hr /><p><br /><span style=\"color: #888888; font-size: 14px; line-height: 30px;\">We go through extensive factory training so that we may provide you with the knowledge you need to make an educated decision in choosing the vehicle that is right for your lifestyle.</span></p><ul class=\"list-style-1\" style=\"margin-top: 15px;\"><li>Stress-free finance department.</li><li>Robust selection of popular vehicles.</li><li>350 offers on site, trusted by a community.</li><li>Maintain your car to stay safe on the road</li><li>We know how to handle a wide range of car services.</li></ul>						</div>\r\n				</div>\r\n					</div>\r\n		</div>\r\n				<div class=\"elementor-column elementor-col-50 elementor-top-column elementor-element elementor-element-075e6ed\" data-id=\"075e6ed\" data-element_type=\"column\">\r\n			<div class=\"elementor-widget-wrap elementor-element-populated\">\r\n						<div class=\"elementor-element elementor-element-a8d0c1a elementor-widget elementor-widget-image\" data-id=\"a8d0c1a\" data-element_type=\"widget\" data-widget_type=\"image.default\">\r\n				<div class=\"elementor-widget-container\">\r\n													<img fetchpriority=\"high\" decoding=\"async\" width=\"529\" height=\"290\" src=\"assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1.jpeg\" class=\"attachment-large size-large wp-image-5754\" alt=\"\" srcset=\"assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1.jpeg 529w, assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1-300x164.jpeg 300w, assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1-327x179.jpeg 327w, assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1-255x140.jpeg 255w, assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1-510x280.jpeg 510w, assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1-280x153.jpeg 280w, assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1-350x192.jpeg 350w, assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1-398x218.jpeg 398w, assets/images/wp-uploads/sites/24/2022/10/about-us-2-529x290-1-275x151.jpeg 275w\" sizes=\"(max-width: 529px) 100vw, 529px\" />													</div>\r\n				</div>\r\n					</div>\r\n		</div>\r\n					</div>\r\n		</section>\r\n				<section class=\"elementor-section elementor-top-section elementor-element elementor-element-2adf9a0 elementor-section-full_width elementor-section-stretched elementor-section-height-default elementor-section-height-default\" data-id=\"2adf9a0\" data-element_type=\"section\" data-settings=\"{&quot;stretch_section&quot;:&quot;section-stretched&quot;,&quot;background_background&quot;:&quot;classic&quot;}\">\r\n						<div class=\"elementor-container elementor-column-gap-default\">\r\n					<div class=\"elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-6646619\" data-id=\"6646619\" data-element_type=\"column\">\r\n			<div class=\"elementor-widget-wrap elementor-element-populated\">\r\n						<section class=\"elementor-section elementor-inner-section elementor-element elementor-element-35e942f elementor-section-boxed elementor-section-height-default elementor-section-height-default\" data-id=\"35e942f\" data-element_type=\"section\">\r\n						<div class=\"elementor-container elementor-column-gap-default\">\r\n					<div class=\"elementor-column