or-widget-container\">\r\n				<div class=\"motors-elementor-widget stm_image_carousel swiper-container\" id=\"stm_image_carousel-71417\">\r\n		<div class=\"swiper-wrapper\">\r\n								<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/09/first-parallax-block-1-270x180.jpg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/08/porsche-1917x554-1-270x180.jpg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/revslider/home_slider1/slide_1-270x180.jpg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/revslider/home_slider1/slide-3-1919x877-270x180.jpg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/10/post_id_2020_media-1-999x652-1-270x180.jpeg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/10/post_id_2020_media-3-999x719-1-270x180.jpeg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/10/post_id_2020_media-4-999x622-1-270x180.jpeg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/10/post_id_2020_media-5-1023x613-1-270x180.jpeg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/10/post_id_2027_ME54t-1917x644-1-270x180.jpeg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/10/post_id_2027_srDqt-999x719-1-270x180.jpeg\" alt=\"Gallery image\">\r\n											</div>\r\n										<div class=\"swiper-slide\">\r\n													<img decoding=\"async\" src=\"assets/images/wp-uploads/sites/24/2022/10/service-1-21-350x205-2-270x180.jpeg\" alt=\"Gallery image\">\r\n											</div>\r\n							</div>\r\n\r\n					<div class=\"stm-swiper-controls\">\r\n									<div class=\"stm-swiper-prev\"><i class=\"fas fa-angle-left\"></i></div>\r\n													<div class=\"swiper-pagination\"></div>\r\n													<div class=\"stm-swiper-next\"><i class=\"fas fa-angle-right\"></i></div>\r\n							</div>\r\n			</div>\r\n	\r\n			</div>\r\n				</div>\r\n					</div>\r\n		</div>\r\n					</div>\r\n		</section>\r\n					</div>\r\n		</div>\r\n					</div>\r\n		</section>\r\n				<section class=\"elementor-section elementor-top-section elementor-element elementor-element-805231c elementor-section-boxed elementor-section-height-default elementor-section-height-default\" data-id=\"805231c\" data-element_type=\"section\">\r\n						<div class=\"elementor-container elementor-column-gap-default\">\r\n					<div class=\"elementor-column elementor-col-50 elementor-top-column elementor-element elementor-element-d2986bb\" data-id=\"d2986bb\" data-element_type=\"column\">\r\n			<div class=\"elementor-widget-wrap elementor-element-populated\">\r\n						<div class=\"elementor-element elementor-element-e4b2556 elementor-widget elementor-widget-heading\" data-id=\"e4b2556\" data-element_type=\"widget\" data-widget_type=\"heading.default\">\r\n				<div class=\"elementor-widget-container\">\r\n			<h3 class=\"elementor-heading-title elementor-size-default\">OUR ADVANTAGES</h3>		</div>\r\n				</div>\r\n				<div class=\"elementor-element elementor-element-9d3ea95 elementor-widget elementor-widget-stm-accordion\" data-id=\"9d3ea95\" data-element_type=\"widget\" data-widget_type=\"stm-accordion.default\">\r\n				<div class=\"elementor-widget-container\">\r\n				<div class=\"stm-elementor-accordion\">\r\n		<div class=\"stm-elementor-accordion-container\">\r\n			<div class=\"stm-elementor-panels-container\">\r\n									<div class=\"stm-elementor-panel active\">\r\n						<div class=\"stm-elementor-panel-heading\" data-heading=\"panel-0\">\r\n							<h4 class=\"stm-elementor-panel-title\">\r\n																		<i class=\"stm-elementor-panel-icon stmicon- stm-icon-car_sale\"></i>\r\n																			<span class=\"panel-title-text\">\r\n									Do You Want to sell a car?								</span>\r\n								<i class=\"stm-elementor-panel-control-icon-chevron fas fa-chevron-down\"></i>\r\n							</h4>\r\n						</div>\r\n						<div class=\"stm-elementor-panel-body\" data-content=\"panel-0\" style=\"display: block;\">\r\n							<div class=\"stm-elementor-panel-content\">\r\n								<div class=\"panel-content-wrap\">\r\n									<p>Whatâ€™s your car worth? Receive the absolute best value for your trade-in vehicle. We even handle all paperwork. Schedule your appointment today!</p>								</div>\r\n							</div>\r\n						</div>\r\n					</div>\r\n									<div class=\"stm-elementor-panel \">\r\n						<div class=\"stm-elementor-panel-heading\" data-heading=\"panel-1\">\r\n							<h4 class=\"stm-elementor-panel-title\">\r\n																		<i class=\"stm-elementor-panel-icon stmicon- stm-icon-key\"></i>\r\n																			<span class=\"panel-title-text\">\r\n									Are You looking for a new car?								</span>\r\n								<i class=\"stm-elementor-panel-control-icon-chevron fas fa-chevron-down\"></i>\r\n							</h4>\r\n						</div>\r\n						<div class=\"stm-elementor-panel-body\" data-content=\"panel-1\" >\r\n							<div class=\"stm-elementor-panel-content\">\r\n								<div class=\"panel-content-wrap\">\r\n									<div id=\"1445