(3, 'faq', 'FAQ', 'Frequently asked questions about buying and selling vehicles.', '<!-- Breads -->\r\n		<div class=\"container\">\r\n\r\n					<div data-elementor-type=\"wp-page\" data-elementor-id=\"2085\" class=\"elementor elementor-2085\">\r\n						<section class=\"elementor-section elementor-top-section elementor-element elementor-element-e918e5b elementor-section-boxed elementor-section-height-default elementor-section-height-default\" data-id=\"e918e5b\" data-element_type=\"section\">\r\n						<div class=\"elementor-container elementor-column-gap-default\">\r\n					<div class=\"elementor-column elementor-col-66 elementor-top-column elementor-element elementor-element-db41fc9\" data-id=\"db41fc9\" data-element_type=\"column\">\r\n			<div class=\"elementor-widget-wrap elementor-element-populated\">\r\n						<div class=\"elementor-element elementor-element-b5b7e90 elementor-widget elementor-widget-accordion\" data-id=\"b5b7e90\" data-element_type=\"widget\" data-widget_type=\"accordion.default\">\r\n				<div class=\"elementor-widget-container\">\r\n			<style>/*! elementor - v3.20.0 - 13-03-2024 */\r\n.elementor-accordion{text-align:left}.elementor-accordion .elementor-accordion-item{border:1px solid #d5d8dc}.elementor-accordion .elementor-accordion-item+.elementor-accordion-item{border-top:none}.elementor-accordion .elementor-tab-title{margin:0;padding:15px 20px;font-weight:700;line-height:1;cursor:pointer;outline:none}.elementor-accordion .elementor-tab-title .elementor-accordion-icon{display:inline-block;width:1.5em}.elementor-accordion .elementor-tab-title .elementor-accordion-icon svg{width:1em;height:1em}.elementor-accordion .elementor-tab-title .elementor-accordion-icon.elementor-accordion-icon-right{float:right;text-align:right}.elementor-accordion .elementor-tab-title .elementor-accordion-icon.elementor-accordion-icon-left{float:left;text-align:left}.elementor-accordion .elementor-tab-title .elementor-accordion-icon .elementor-accordion-icon-closed{displa